(function () {
	if (typeof DataTable === 'undefined') return;

	document.addEventListener('DOMContentLoaded', function () {
		document.querySelectorAll('table[data-p2-datatables="1"]').forEach(function (el) {
			if (el.classList.contains('dataTable')) return;

			let opts = { responsive: true };

			const json = el.getAttribute('data-p2-datatables-options');
			if (json) {
				try { opts = Object.assign(opts, JSON.parse(json)); } catch (e) {}
			}

			new DataTable(el, opts);
		});
	});
})();
